cd /home/archon/FormalizationProjects/Algebraic-Jacobian-Challenge
python3 -c "
import json
d=json.load(open('.archon/logs/iter-239/blueprint-doctor.json'))
import sys
def walk(o,p=''):
    if isinstance(o,dict):
        for k,v in o.items(): walk(v,p+'/'+k)
    elif isinstance(o,list):
        for i,v in enumerate(o): walk(v,p+f'[{i}]')
    else:
        if 'IdentityComponent' in str(o) or 'identity' in str(o).lower():
            print(p,'=',o)
" 2>/dev/null | grep -i 'identitycomp\|bare' | head -40
echo "--- try grep raw ---"
grep -o 'Picard_IdentityComponent[^\"]*' .archon/logs/iter-239/blueprint-doctor.json | head

